        <NavigationLinks collapsed={isSidebarCollapsed} />
      </div>
      <div className="border-t p-3">
        <p
          className={cn(
            "px-3 text-xs text-muted-foreground",
            isSidebarCollapsed && "sr-only"
          )}
        >
          © 2026 Inventory Flow
        </p>
      </div>
    </aside>
  )
}

