        Assert.Equal(HttpStatusCode.Conflict, overdraft.StatusCode);
        var balance = Assert.Single(await balances.Content.ReadFromJsonAsync<List<InventoryBalanceResponse>>() ?? []);
        Assert.Equal(1.2500m, balance.Quantity);
