     6	/// <summary>Identifies the direction of an inventory ledger entry.</summary>
     7	public enum InventoryMovementType
     8	{
     9	    Receipt = 1,
    10	    Issue = 2
    11	}
    12	
    13	/// <summary>Represents an immutable, idempotent inventory ledger entry.</summary>
    14	public sealed class InventoryMovement : Entity<Guid>
    15	{
    16	    /// <summary>Maximum quantity representable by the inventory decimal(18,4) columns.</summary>
    17	    public const decimal MaxQuantity = 99999999999999.9999m;
    18	
    19	    /// <summary>Maximum length of a client supplied idempotency key.</summary>
    20	    public const int IdempotencyKeyMaxLength = 100;
    21	
    22	    /// <summary>Initializes an inventory movement.</summary>
    23	    public InventoryMovement(Guid id, Guid workspaceId, Guid warehouseId, Guid productId, InventoryMovementType type,
    24	        decimal quantity, string idempotencyKey, decimal balanceAfterQuantity, DateTimeOffset occurredAtUtc) : base(id)
    25	    {
    26	        if (id == Guid.Empty || workspaceId == Guid.Empty || warehouseId == Guid.Empty || productId == Guid.Empty)
    27	            throw new DomainException("Inventory movement identifiers are required.");
    28	        if (!Enum.IsDefined(type)) throw new DomainException("Inventory movement type is invalid.");
    29	        Quantity = ValidateQuantity(quantity);
    30	        IdempotencyKey = NormalizeIdempotencyKey(idempotencyKey);
    31	        if (balanceAfterQuantity < 0m || decimal.Round(balanceAfterQuantity, 4) != balanceAfterQuantity ||
    32	            balanceAfterQuantity > MaxQuantity)
    33	            throw new DomainException("Inventory balance must be nonnegative, have at most four decimal places, and not exceed 99999999999999.9999.");
    34	        if (occurredAtUtc.Offset != TimeSpan.Zero) throw new DomainException("Inventory movement time must be in UTC.");
    35	
    36	        WorkspaceId = workspaceId;
    37	        WarehouseId = warehouseId;
    38	        ProductId = productId;
    39	        Type = type;
    40	        BalanceAfterQuantity = balanceAfterQuantity;
    41	        OccurredAtUtc = occurredAtUtc;
    42	    }
    43	
    44	    /// <summary>Gets the owning workspace identifier.</summary>
    45	    public Guid WorkspaceId { get; private set; }
    46	    /// <summary>Gets the warehouse identifier.</summary>
    47	    public Guid WarehouseId { get; private set; }
    48	    /// <summary>Gets the product identifier.</summary>
    49	    public Guid ProductId { get; private set; }
    50	    /// <summary>Gets the direction of the movement.</summary>
    51	    public InventoryMovementType Type { get; private set; }
    52	    /// <summary>Gets the positive movement quantity.</summary>
    53	    public decimal Quantity { get; private set; }
    54	    /// <summary>Gets the client-supplied idempotency key.</summary>
    55	    public string IdempotencyKey { get; private set; }
    56	    /// <summary>Gets the resulting balance immediately after this movement.</summary>
    57	    public decimal BalanceAfterQuantity { get; private set; }
    58	    /// <summary>Gets the UTC instant at which the movement was recorded.</summary>
    59	    public DateTimeOffset OccurredAtUtc { get; private set; }
    60	
    61	    /// <summary>Validates a positive decimal quantity representable by inventory decimal(18,4) columns.</summary>
    62	    public static decimal ValidateQuantity(decimal quantity)
    63	    {
    64	        if (quantity <= 0m || decimal.Round(quantity, 4) != quantity || quantity > MaxQuantity)
    65	            throw new DomainException("Inventory quantity must be positive, have at most four decimal places, and not exceed 99999999999999.9999.");
    66	        return quantity;
    67	    }
    68	
    69	    /// <summary>Normalizes and validates an idempotency key.</summary>
    70	    public static string NormalizeIdempotencyKey(string idempotencyKey)
    71	    {
    72	        var value = idempotencyKey?.Trim() ?? string.Empty;
    73	        if (string.IsNullOrWhiteSpace(value) || value.Length > IdempotencyKeyMaxLength)
    74	            throw new DomainException($"Idempotency key must contain between 1 and {IdempotencyKeyMaxLength} characters.");
    75	        return value;
    76	    }
    77	}
