    16	        builder.Property(movement => movement.Quantity).HasPrecision(18, 4).IsRequired();
    17	        builder.Property(movement => movement.BalanceAfterQuantity).HasPrecision(18, 4).IsRequired();
    18	        builder.Property(movement => movement.IdempotencyKey).HasMaxLength(InventoryMovement.IdempotencyKeyMaxLength).IsRequired();
    19	        builder.Property(movement => movement.OccurredAtUtc).IsRequired();
    20	        builder.HasIndex(movement => new { movement.WorkspaceId, movement.IdempotencyKey }).IsUnique();
    21	        builder.HasIndex(movement => new { movement.WorkspaceId, movement.WarehouseId, movement.ProductId, movement.OccurredAtUtc });
    22	        builder.HasOne<Workspace>().WithMany().HasForeignKey(movement => movement.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
