    29	    /// <summary>Records a decimal receipt once, prevents an overdraft, and exposes the resulting balance.</summary>
    30	    [Fact]
    31	    public async Task Inventory_ReceiptIssueAndBalance_AreIdempotentAndNonnegative()
    32	    {
    33	        var session = await RegisterSessionAsync();
    34	        var suffix = Guid.NewGuid().ToString("N");
    35	        var warehouse = await PostAsync<WarehouseResponse>("/api/warehouses", session.AccessToken, new CreateWarehouseRequest($"Warehouse {suffix}"));
    36	        var product = await PostAsync<ProductResponse>("/api/products", session.AccessToken, new CreateProductRequest($"Product {suffix}", $"SKU-{suffix}"));
    37	        var receiptRequest = new RecordInventoryMovementRequest(warehouse.Id, product.Id, 2.5000m, $"receipt-{suffix}");
    38	
    39	        using var receipt = await SendAsync(HttpMethod.Post, "/api/inventory/receipts", session.AccessToken, receiptRequest);
    40	        using var duplicateReceipt = await SendAsync(HttpMethod.Post, "/api/inventory/receipts", session.AccessToken, receiptRequest);
    41	        using var issue = await SendAsync(HttpMethod.Post, "/api/inventory/issues", session.AccessToken,
    42	            new RecordInventoryMovementRequest(warehouse.Id, product.Id, 1.2500m, $"issue-{suffix}"));
    43	        using var overdraft = await SendAsync(HttpMethod.Post, "/api/inventory/issues", session.AccessToken,
    44	            new RecordInventoryMovementRequest(warehouse.Id, product.Id, 1.2501m, $"overdraft-{suffix}"));
    45	        using var balances = await SendAsync(HttpMethod.Get, $"/api/inventory/balances?warehouseId={warehouse.Id}", session.AccessToken);
    46	
    47	        Assert.Equal(HttpStatusCode.Created, receipt.StatusCode);
    48	        Assert.Equal(HttpStatusCode.Created, duplicateReceipt.StatusCode);
    49	        Assert.Equal(HttpStatusCode.Created, issue.StatusCode);
    50	        Assert.Equal(HttpStatusCode.Conflict, overdraft.StatusCode);
    51	        var balance = Assert.Single(await balances.Content.ReadFromJsonAsync<List<InventoryBalanceResponse>>() ?? []);
    52	        Assert.Equal(1.2500m, balance.Quantity);
    53	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
    54	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    55	        Assert.Equal(2, await dbContext.InventoryMovements.CountAsync(movement => movement.WorkspaceId == session.User.Workspace.Id));
    56	    }
